	.TITLE	RASTER	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df driversSM100	=	0; Variables; ---------	.LOC	0OFLAGS:	.BLKB	2		; flags diversOLUPTS:	.BLKB	4		; ^matrice du lutinOLUPTC:	.BLKB	4		; ^matrice du fondOLUPTF:	.BLKB	4		; ^fond de l'cranOLUPTO:	.BLKB	4		; ^pour oprationsOLUOLD:	.BLKB	4		; ancienne positionOLUNEW:	.BLKB	4		; nouvelle positionOLUORI:	.BLKB	4		; origine du mouvementOLULGX:	.BLKB	2		; largeur du lutinOLULGY:	.BLKB	2		; hauteur du lutinOLUIYF:	.BLKB	4		; Iy pour OLUPTFOLUIYO:	.BLKB	4		; Iy pour OLUPTOLGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.B	D3,#2	.W	LIB,?MOUSE	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	ER	LOAD.L	A6,A4		; A6 <-- ^variables	CLR.B	(A6)+OFLAGS	; clear tous les flagsJUMP	ESSAI	; <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<	LOAD.L	A0,#R16"MOTIF	CLR.L	D0	LOAD.L	A3,#H'4	LOAD.W	D1,#50	SWAP.W	D1	LOAD.W	D1,#2	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTMD	LOAD.W	D0,#50	SWAP.W	D0	LOAD.W	D0,#2	LOAD.W	D1,#50	SWAP.W	D1	LOAD.W	D1,#32	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTDD	LOAD.W	D0,#50	SWAP.W	D0	LOAD.W	D0,#32	LOAD.W	D1,#50	SWAP.W	D1	LOAD.W	D1,#100	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTDD	LOAD.W	D0,#50	SWAP.W	D0	LOAD.W	D0,#100	LOAD.W	D1,#50	SWAP.W	D1	LOAD.W	D1,#129	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTDD	.W	LIB,?GETCAR	COMP.B	D3,#'1	JUMP,EQ	50$	COMP.B	D3,#'2	JUMP,EQ	ESSAI10$:	LOAD.L	A0,#R16"MOTIF	CLR.L	D0	LOAD.L	A3,#H'4	LOAD.W	D1,#100	SWAP.W	D1	LOAD.W	D1,#020$:	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTMD	.W	LIB,?GETCAR	COMP.B	D3,#END	JUMP,EQ	RETOUR	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTMD	INC.W	D1	SWAP.W	D1	INC.W	D1	SWAP.W	D1	JUMP	20$50$:	LOAD.L	A0,#R16"MOTIF	CLR.L	D0	LOAD.L	A3,#H'4	LOAD.W	D1,#100	SWAP.W	D1	LOAD.W	D1,#260$:	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTMD	.W	LIB,?GETCAR	COMP.B	D3,#END	JUMP,EQ	RETOUR	LOAD.W	D2,#16-1	LOAD.W	D3,#16	LOAD.B	D4,#INVDOT	CALL	RASTMD	INC.W	D0	COMP.W	D0,#8	JUMP,LO	60$	CLR.W	D0	JUMP	60$ER:	PUSH.W	D7		; sauve l'erreur	.W	LIB,?AFCR	; passe  la ligne	POP.W	D7		; reprend l'erreur	.W	LIB,?AFERROR	; affiche l'erreur	.W	LIB,?GETCAR	; attend une toucheRETOUR:	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la fentre	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; avorte le processus ...ESSAI:	LOAD.B	D3,#AFCCMO	.W	LIB,?AFCAR	LOAD.W	D3,#0	SWAP.W	D3	LOAD.W	D3,#50	LOAD.W	D4,#350	SWAP.W	D4	LOAD.W	D4,#0	LOAD.W	D2,#SETDOT	.W	LIB,?DRSEG	LOAD.L	D3,#-1	LOAD.L	D4,#-1	.W	LIB,?DRMDEF	LOAD.W	D3,#100	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'AA55AA55	LOAD.L	D4,#H'AA55AA55	.W	LIB,?DRMDEF	LOAD.W	D3,#100	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'AAAAAAAA	LOAD.L	D4,#H'AAAAAAAA	.W	LIB,?DRMDEF	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'88002200	LOAD.L	D4,#H'88002200	.W	LIB,?DRMDEF	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.W	D4,#50	SWAP.W	D4	LOAD.W	D4,#50	CLR.W	D010$:	LOAD.B	D1,D0	INC.B	D1	LOAD.L	A4,#R16"MOTS1	LOAD.L	A3,#R16"MOTC1	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS2	LOAD.L	A3,#R16"MOTC2	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS5	LOAD.L	A3,#R16"MOTC5	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS4	LOAD.L	A3,#R16"MOTC4	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS3	LOAD.L	A3,#R16"MOTC3	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS3	LOAD.L	A3,#R16"MOTC31	DEC.B	D1	JUMP,EQ	15$	CLR.W	D0	JUMP	10$15$:	CALL	FSPRITE		; dessine le premier	JUMP,NE	ER20$:	.W	LIB,?GETKEY	TEST.L	D3:#BKPSEUDO	JUMP,BS	20$	COMP.W	D3,#END	JUMP,EQ	RETOUR	COMP.W	D3,#KEYMGP	JUMP,EQ	50$	COMP.W	D3,#KEYMPO	JUMP,NE	20$	.W	LIB,?IFMOUSE	JUMP,NE	20$	SWAP.W	D4	ADD.W	D4,#16	SWAP.W	D4	CALL	MSPRITE		; dplace	JUMP	20$50$:	CALL	LSPRITE		; efface le dernier	INC.W	D0	JUMP	10$;--------\; FSPRITE >;========/; Dessine le premier lutin.; in	D4.L	premire coordonne;	A4.L	^matrice du lutin (set);	A3.L	^matrice du fond (clear); out	D7.W	erreur; mod	D7.WFSPRITE:	PUSHM.L	D0,D1,D2,D3,D4,A0,A1,A3,A4,A5	LOAD.L	(A6)+OLUOLD,D4	LOAD.W	D7,#ERDIIL	; D7 <-- illgal	LOAD.B	D0,(A4)+0	COMP.B	D0,(A3)+0	; mme largeur ?	JUMP,NE	90$		; non => 90$	LOAD.B	D0,(A4)+1	COMP.B	D0,(A3)+1	; mme hauteur ?	JUMP,NE	90$		; non => 90$	ADD.L	A4,#2	LOAD.L	(A6)+OLUPTS,A4	; mm. ^matrice du lutin	SUB.L	A4,#2	ADD.L	A3,#2	LOAD.L	(A6)+OLUPTC,A3	; mm. ^matrice du fond	SUB.L	A3,#2	CLR.L	D0	LOAD.B	D0,(A4)+1	; D0 <-- hauteur du lutin	LOAD.W	(A6)+OLULGY,D0	LOAD.B	D0,(A4)+0	; D0 <-- largeur du lutin	LOAD.W	(A6)+OLULGX,D0	ADD.W	D0,#8-1	SR.W	D0,#3		; D0 <-- largeur en bytes	LOAD.L	(A6)+OLUIYF,D0	SL.W	D0,#1	LOAD.L	(A6)+OLUIYO,D0	LOAD.W	D4,(A6)+OLUIYF+2	MUL.WU	D4,(A6)+OLULGY	LOAD.L	D0,D4	MUL.WU	D4,#1+4	LOAD.W	D1,#MTYPCP	; D1 <-- type compte mmoire	.W	GESMEM,?GETMEM	; demande mmoire tampon	JUMP,NE	90$	LOAD.L	(A6)+OLUPTF,A4	; mm ^pour fond de l'cran	ADD.L	A4,D0	LOAD.L	(A6)+OLUPTO,A4	; mm ^pour oprations	LOAD.L	D0,(A6)+OLUOLD	LOAD.L	A1,(A6)+OLUPTF	CLR.L	D1	LOAD.L	A5,(A6)+OLUIYF	LOAD.W	D3,(A6)+OLULGY	LOAD.W	D2,(A6)+OLULGX	LOAD.B	D4,#SETDOT	CALL	RASTCLR	CALL	RASTDM		; sauve le fond	LOAD.L	A0,(A6)+OLUPTC	CLR.L	D0	LOAD.L	A3,(A6)+OLUIYF	LOAD.L	D1,(A6)+OLUOLD	LOAD.B	D4,#CLRDOT	CALL	RASTMD		; dessine le fond du motif	LOAD.L	A0,(A6)+OLUPTS	LOAD.B	D4,#SETDOT	CALL	RASTMD		; dessine le contenu du motif	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D0,D1,D2,D3,D4,A0,A1,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;--------\; MSPRITE >;========/; Dplace un lutin.; in	D4.L	nouvelle coordonne; out	-; mod	-MSPRITE:	PUSHM.L	D0,D1,D2,D3,D4,A0,A1,A3,A5	LOAD.L	(A6)+OLUNEW,D4	LOAD.W	D0,(A6)+OLUOLD+0 ; D0 <-- Y le plus petit	LOAD.W	D3,(A6)+OLUNEW+0	COMP.W	D0,D3	JUMP,LS	10$	EX.L	D0,D3		; D0 <-- Y le plus petit10$:	SUB.W	D3,D0		; D3 <-- |diffrence|	SWAP.W	D0	LOAD.W	D1,(A6)+OLUOLD+2 ; D1 <-- X le plus petit	LOAD.W	D2,(A6)+OLUNEW+2	COMP.W	D1,D2	JUMP,LS	15$	EX.L	D1,D2		; D1 <-- X le plus petit15$:	SUB.W	D2,D1		; D2 <-- |diffrence|	LOAD.W	D0,D1	COMP.W	D2,(A6)+OLULGX	; intersection avec l'ancien ?	JUMP,HS	50$		; non => 50$	COMP.W	D3,(A6)+OLULGY	JUMP,HS	50$	ADD.W	D2,(A6)+OLULGX	; D2 <-- largeur	ADD.W	D3,(A6)+OLULGY	; D3 <-- hauteur	LOAD.L	(A6)+OLUORI,D0	LOAD.L	A1,(A6)+OLUPTO	CLR.L	D1	LOAD.L	A5,(A6)+OLUIYO	LOAD.B	D4,#SETDOT	CALL	RASTCLR	CALL	RASTDM		; cran --> buffer oprations	PUSHM.L	D2,D3	LOAD.W	D3,(A6)+OLULGY	LOAD.W	D2,(A6)+OLULGX	LOAD.L	A0,(A6)+OLUPTS	CLR.L	D0	LOAD.L	A3,(A6)+OLUIYF	LOAD.L	A1,(A6)+OLUPTO	LOAD.W	D1,(A6)+OLUOLD+0	SUB.W	D1,(A6)+OLUORI+0	SWAP.W	D1	LOAD.W	D1,(A6)+OLUOLD+2	SUB.W	D1,(A6)+OLUORI+2	LOAD.L	A5,(A6)+OLUIYO	LOAD.B	D4,#CLRDOT	CALL	RASTMM		; efface le motif	LOAD.L	A0,(A6)+OLUPTF	CLR.L	D0	LOAD.L	A3,(A6)+OLUIYF	LOAD.B	D4,#SETDOT	CALL	RASTMM		; remet le fond	LOAD.L	A0,(A6)+OLUPTO	LOAD.W	D0,(A6)+OLUNEW+0	SUB.W	D0,(A6)+OLUORI+0	SWAP.W	D0	LOAD.W	D0,(A6)+OLUNEW+2	SUB.W	D0,(A6)+OLUORI+2	LOAD.L	A3,(A6)+OLUIYO	LOAD.L	A1,(A6)+OLUPTF	CLR.L	D1	LOAD.L	A5,(A6)+OLUIYF	LOAD.B	D4,#SETDOT	CALL	RASTCLR	CALL	RASTMM		; sauve le nouveau fond	LOAD.L	D1,D0	LOAD.L	A0,(A6)+OLUPTC	CLR.L	D0	LOAD.L	A3,(A6)+OLUIYF	LOAD.L	A1,(A6)+OLUPTO	LOAD.L	A5,(A6)+OLUIYO	LOAD.B	D4,#CLRDOT	CALL	RASTMM		; met le fond du nouveau motif	LOAD.L	A0,(A6)+OLUPTS	LOAD.B	D4,#SETDOT	CALL	RASTMM		; met le contenu du nouveau motif	POPM.L	D2,D3	LOAD.L	D0,(A6)+OLUORI	CLR.L	D1	LOAD.B	D4,#INVDOT	CALL	RASTDM		; xor avec l'cran (astuce)	EX.L	D0,D1	EX.L	A0,A1	EX.L	A3,A5	CALL	RASTMD		; remet dans l'cran	JUMP	80$50$:	LOAD.W	D2,(A6)+OLULGX	LOAD.W	D3,(A6)+OLULGY	LOAD.L	D0,(A6)+OLUOLD	LOAD.L	A1,(A6)+OLUPTF	CLR.L	D1	LOAD.L	A5,(A6)+OLUIYF	LOAD.B	D4,#INVDOT	CALL	RASTDM		; xor avec l'cran (astuce)	EX.L	A0,A1	EX.L	D0,D1	EX.L	A3,A5	CALL	RASTMD		; remet l'ancien fond dans l'cran	LOAD.L	D0,(A6)+OLUNEW	LOAD.L	A1,(A6)+OLUPTF	CLR.L	D1	LOAD.L	A5,(A6)+OLUIYF	LOAD.B	D4,#SETDOT	CALL	RASTCLR	CALL	RASTDM		; sauve le fond	LOAD.L	A0,(A6)+OLUPTC	CLR.L	D0	LOAD.L	A3,(A6)+OLUIYF	LOAD.L	D1,(A6)+OLUNEW	LOAD.B	D4,#CLRDOT	CALL	RASTMD		; dessine le fond du nouveau motif	LOAD.L	A0,(A6)+OLUPTS	LOAD.B	D4,#SETDOT	CALL	RASTMD		; dessine le contenu du nouveau motif80$:	LOAD.L	(A6)+OLUOLD,(A6)+OLUNEW	POPM.L	D0,D1,D2,D3,D4,A0,A1,A3,A5	RET;--------\; LSPRITE >;========/; Efface le dernier lutin.; in	-; out	D7.W	erreur; mod	D7.WLSPRITE:	PUSHM.L	D0,D1,D2,D3,D4,A0,A1,A3,A4,A5	LOAD.L	A0,(A6)+OLUPTS	CLR.L	D0	LOAD.L	A3,(A6)+OLUIYF	LOAD.L	D1,(A6)+OLUOLD	LOAD.W	D2,(A6)+OLULGX	LOAD.W	D3,(A6)+OLULGY	LOAD.B	D4,#CLRDOT	CALL	RASTMD		; efface le lutin	LOAD.L	A0,(A6)+OLUPTF	LOAD.B	D4,#SETDOT	CALL	RASTMD		; remet le fond	LOAD.L	A4,(A6)+OLUPTF	; A4 <-- ^dbut tranche mmoire	LOAD.W	D1,#MTYPCP	; D1 <-- type compte mmoire	.W	GESMEM,?GIVMEM	; rend la mmoire	POPM.L	D0,D1,D2,D3,D4,A0,A1,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;--------\; RASTCLR >;========/; Efface (rempli de zro) la destination.; in	A1.L	^mmoire destination;	A5.L	Iy destination;	D2.W	largeur (x);	D3.W	hauteur (y); out	-; mod	-RASTCLR:	PUSHM.L	D0,D1,D2,D3,A0,A1	LOAD.W	D1,D2	ADD.W	D1,#7	SR.W	D1,#3		; D1 <-- largeur en bytes30$:	LOAD.L	A0,A1	LOAD.W	D0,D140$:	CLR.B	(A0+)		; efface une ligne	DEC.W	D0	JUMP,NE	40$	ADD.L	A1,A5		; A1 <-- ^ligne en dessous	DEC.W	D3	JUMP,NE	30$	POPM.L	D0,D1,D2,D3,A0,A1	RET;--------\; RASTMM  >;========/; Dplace une surface rectangulaire mmoire --> mmoire.; in	----;	A0.L	^mmoire source;	D0.L	coordonne source (y;x);	A3.L	Iy source;	----;	A1.L	^mmoire destination;	D1.L	coordonne destination (y;x);	A5.L	Iy destination;	----;	D2.W	largeur (x);	D3.W	hauteur (y);	D4.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTMM:	PUSHM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5,A6	LOAD.L	D5,D0	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,A3	MUL.WU	D5,D6		; D5 <-- Y*Iy	ADD.L	A0,D5		; A0 <-- ajoute offset Y	LOAD.W	D5,D0		; D5 <-- X	SR.W	D5,#3	ADD.L	A0,D5		; A0 <-- ajoute offset X	AND.W	D0,#7		; D0 <-- no du bit dans le byte	LOAD.L	A2,#H'1		; A2 <-- Ix	LOAD.L	D5,D1	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,A5	MUL.WU	D5,D6		; D5 <-- Y*Iy	ADD.L	A1,D5		; A1 <-- ajoute offset Y	LOAD.W	D5,D1		; D5 <-- X	SR.W	D5,#3	ADD.L	A1,D5		; A1 <-- ajoute offset X	AND.W	D1,#7		; D1 <-- no du bit dans le byte	LOAD.L	A4,#H'1		; A4 <-- Ix	JUMP	RASTEROP;--------\; RASTMD  >;========/; Dplace une surface rectangulaire mmoire --> cran.; in	----;	A0.L	^mmoire source;	D0.L	coordonne source (y;x);	A3.L	Iy source;	----;	D1.L	coordonne destination (y;x);	----;	D2.W	largeur (x);	D3.W	hauteur (y);	D4.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTMD:	PUSHM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5,A6	LOAD.L	D5,D0	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,A3	MUL.WU	D5,D6		; D5 <-- Y*Iy	ADD.L	A0,D5		; A0 <-- ajoute offset Y	LOAD.W	D5,D0		; D5 <-- X	SR.W	D5,#3	ADD.L	A0,D5		; A0 <-- ajoute offset X	AND.W	D0,#7		; D0 <-- no du bit dans le byte	LOAD.L	A2,#H'1		; A2 <-- Ix	.IF	SM100	LOAD.L	A1,H'093A	; A1 <-- adresse dbut cran	LOAD.W	D5,D1		; D5 <-- X	AND.L	D5,#1024-1	; masque coordonne	SR.L	D5,#3	ADD.L	A1,D5		; ajoute offset X	LOAD.L	D5,D1	SWAP.W	D5		; D5 <-- Y	AND.L	D5,#512-1	; masque coordonne	SL.L	D5,#7	ADD.L	A1,D5		; ajoute offset Y	AND.W	D1,#H'7		; D1 <-- no du bit dans le byte	LOAD.L	A4,#H'1		; A2 <-- Ix	LOAD.L	A5,#H'80	; A3 <-- Iy	.ELSE	LOAD.L	D5,D1	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,D1		; D6 <-- X	AND.L   D5,#H'3FF	; bits significatifs de Y	AND.L	D6,#H'3F8	; bits colonnes de X	SL.L	D6,#7	OR.L	D5,D6	TSET.L	D5:#19.		; bit d'adresse dans le bitmap	LOAD.L	A1,D5		; A1 <-- adresse du byte	AND.W	D1,#H'7		; D1 <-- no du bit dans le byte	LOAD.L	A4,#H'400	; A4 <-- Ix	LOAD.L	A5,#H'1		; A5 <-- Iy	.ENDIF	JUMP	RASTEROP;--------\; RASTDM  >;========/; Dplace une surface rectangulaire cran --> mmoire.; in	----;	D0.L	coordonne source (y;x);	----;	A1.L	^mmoire destination;	D1.L	coordonne destination (y;x);	A5.L	Iy destination;	----;	D2.W	largeur (x);	D3.W	hauteur (y);	D4.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTDM:	PUSHM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5,A6	.IF	SM100	LOAD.L	A0,H'093A	; A0 <-- adresse dbut cran	LOAD.W	D5,D0		; D5 <-- X	AND.L	D5,#1024-1	; masque coordonne	SR.L	D5,#3	ADD.L	A0,D5		; ajoute offset X	LOAD.L	D5,D0	SWAP.W	D5		; D5 <-- Y	AND.L	D5,#512-1	; masque coordonne	SL.L	D5,#7	ADD.L	A0,D5		; ajoute offset Y	AND.W	D0,#H'7		; D0 <-- no du bit dans le byte	LOAD.L	A2,#H'1		; A2 <-- Ix	LOAD.L	A3,#H'80	; A3 <-- Iy	.ELSE	LOAD.L	D5,D0	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,D0		; D6 <-- X	AND.L   D5,#H'3FF	; bits significatifs de Y	AND.L	D6,#H'3F8	; bits colonnes de X	SL.L	D6,#7	OR.L	D5,D6	TSET.L	D5:#19.		; bit d'adresse dans le bitmap	LOAD.L	A0,D5		; A0 <-- adresse du byte	AND.W	D0,#H'7		; D0 <-- no du bit dans le byte	LOAD.L	A2,#H'400	; A2 <-- Ix	LOAD.L	A3,#H'1		; A3 <-- Iy	.ENDIF	LOAD.L	D5,D1	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,A5	MUL.WU	D5,D6		; D5 <-- Y*Iy	ADD.L	A1,D5		; A1 <-- ajoute offset Y	LOAD.W	D5,D1		; D5 <-- X	SR.W	D5,#3	ADD.L	A1,D5		; A1 <-- ajoute offset X	AND.W	D1,#7		; D1 <-- no du bit dans le byte	LOAD.L	A4,#H'1		; A4 <-- Ix	JUMP	RASTEROP;--------\; RASTDD  >;========/; Dplace une surface rectangulaire cran --> cran.; in	----;	D0.L	coordonne source (y;x);	----;	D1.L	coordonne destination (y;x);	----;	D2.W	largeur (x);	D3.W	hauteur (y);	D4.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTDD:	PUSHM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5,A6	.IF	SM100	LOAD.L	A0,H'093A	; A0 <-- adresse dbut cran	LOAD.W	D5,D0		; D5 <-- X	AND.L	D5,#1024-1	; masque coordonne	SR.L	D5,#3	ADD.L	A0,D5		; ajoute offset X	LOAD.L	D5,D0	SWAP.W	D5		; D5 <-- Y	AND.L	D5,#512-1	; masque coordonne	SL.L	D5,#7	ADD.L	A0,D5		; ajoute offset Y	AND.W	D0,#H'7		; D0 <-- no du bit dans le byte	LOAD.L	A2,#H'1		; A2 <-- Ix	LOAD.L	A3,#H'80	; A3 <-- Iy	.ELSE	LOAD.L	D5,D0	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,D0		; D6 <-- X	AND.L   D5,#H'3FF	; bits significatifs de Y	AND.L	D6,#H'3F8	; bits colonnes de X	SL.L	D6,#7	OR.L	D5,D6	TSET.L	D5:#19.		; bit d'adresse dans le bitmap	LOAD.L	A0,D5		; A0 <-- adresse du byte	AND.W	D0,#H'7		; D0 <-- no du bit dans le byte	LOAD.L	A2,#H'400	; A2 <-- Ix	LOAD.L	A3,#H'1		; A3 <-- Iy	.ENDIF	.IF	SM100	LOAD.L	A1,H'093A	; A1 <-- adresse dbut cran	LOAD.W	D5,D1		; D5 <-- X	AND.L	D5,#1024-1	; masque coordonne	SR.L	D5,#3	ADD.L	A1,D5		; ajoute offset X	LOAD.L	D5,D1	SWAP.W	D5		; D5 <-- Y	AND.L	D5,#512-1	; masque coordonne	SL.L	D5,#7	ADD.L	A1,D5		; ajoute offset Y	AND.W	D1,#H'7		; D1 <-- no du bit dans le byte	LOAD.L	A4,#H'1		; A2 <-- Ix	LOAD.L	A5,#H'80	; A3 <-- Iy	.ELSE	LOAD.L	D5,D1	SWAP.W	D5		; D5 <-- Y	LOAD.W	D6,D1		; D6 <-- X	AND.L   D5,#H'3FF	; bits significatifs de Y	AND.L	D6,#H'3F8	; bits colonnes de X	SL.L	D6,#7	OR.L	D5,D6	TSET.L	D5:#19.		; bit d'adresse dans le bitmap	LOAD.L	A1,D5		; A1 <-- adresse du byte	AND.W	D1,#H'7		; D1 <-- no du bit dans le byte	LOAD.L	A4,#H'400	; A2 <-- Ix	LOAD.L	A5,#H'1		; A3 <-- Iy	.ENDIF;	JUMP	RASTEROPRASTEROP:	LOAD.L	A6,#R16"OPRAST	; A6 <-- ^instruction SET	COMP.B	D4,#SETDOT	JUMP',EQ 10$	ADD.L	A6,#2+2		; A6 <-- ^instruction CLR	COMP.B	D4,#CLRDOT	JUMP',EQ 10$	ADD.L	A6,#2+2		; A6 <-- ^instruction XOR10$:	LOAD.L	D4,(A6)		; D4 <-- 2 instructions	LOAD.L	A6,#R16"RASTER	LOAD.L	(A6)+ADRAST1,D4	LOAD.L	(A6)+ADRAST2,D4	LOAD.L	(A6)+ADRAST3,D4	LOAD.L	(A6)+ADRAST4,D4	LOAD.L	(A6)+ADRAST5,D4	LOAD.L	(A6)+ADRAST6,D4	LOAD.L	(A6)+ADRAST7,D4;	JUMP	RASTER;---------\; RASTER   >;---------/; Dplace rapidement une surface rectangulaire dans l'cran; ou dans la mmoire.; in	A0.L	^source;	D0.B	Ds adresse bit source (0..7);	A2.L	Ix source (1..n);	A3.L	Iy source (1..n);;	A1.L	^destination;	D1.B	Dd adresse bit destination (0..7);	A4.L	Ix destination (1..n);	A5.L	Iy destination (1..n);;	D2.W	Lx largeur (8..n);	D3.W	Ly hauteur (8..n); out	-; mod	-RASTER:	LOAD.W	D6,A2		; D6 <-- Ix source	COMP.B	D0,D1		; Ds = Dd ?	JUMP',NE 05$		; non => 05$	CLR.W	D6		; oui => byte droite = gauche; Effectue le travail de dbut.05$:	TEST.B	D1		; Dd = 0 ?	JUMP,EQ	20$		; oui => 20$				; non =>	PUSHM.L	D3,A0,A1	COMP.B	D0,D1	JUMP',HI 14$10$:				; Ds <= Dd :	LOAD.B	D4,(A0)		; D4 <-- byte source	.IF	SM100	SL.B	D4,D0		; D4 <--  gauche de Ds	SR.B	D4,D1		; D4 <--  droite de Dd	.ELSE	SR.B	D4,D0		; D4 <--  gauche de Ds	SL.B	D4,D1		; D4 <--  droite de Dd	.ENDIF1$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	10$	JUMP'	18$14$:				; Ds > Dd :	.IF	SM100	LOAD.B	D5,#8	ADD.B	D5,D1		; D5 <-- Dd+8	.ENDIF15$:	.IF	SM100	LOAD.B	D4,(A0)	SL.W	D4,#8	LOAD.B	D4,(A0)+(D6.W)	; D4 <-- word source	.ELSE	LOAD.B	D4,(A0)+(D6.W)	SL.W	D4,#8	LOAD.B	D4,(A0)		; D4 <-- word source	.ENDIF	.IF	SM100	SL.W	D4,D0		; D4 <--  gauche de Ds	SR.W	D4,D5		; D4 <--  droite de Dd+8	.ELSE	SR.W	D4,D0		; D4 <--  gauche de Ds	SL.B	D4,D1		; D4 <--  droite de Dd	.ENDIF2$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	15$18$:	POPM.L	D3,A0,A1	SUB.W	D2,#8	ADD.W	D2,D1		; D2 <-- enlve 8-Dd	ADD.L	A1,A4		; A1 <-- ^plus  droite	COMP.B	D0,D1	JUMP',LO 20$	ADD.L	A0,A2		; A0 <-- ^plus  droite; Effectue le travail du milieu.20$:	LOAD.W	D7,D2	SR.W	D7,#3		; D7 <-- nb bytes	JUMP,EQ	50$	.IF	SM100	LOAD.B	D5,D1	SUB.B	D5,D0		; D5 <-- Dd-Ds	JUMP',HS 25$	ADD.B	D5,#8		; D5 <-- 8-(Ds-Dd)	.ELSE	LOAD.B	D5,D0	SUB.B	D5,D1		; D5 <-- Ds-Dd	JUMP',HS 25$	ADD.B	D5,#8		; D5 <-- 8-(Dd-Ds)	.ENDIF25$:	PUSHM.L	D3,A0,A130$:	.IF	SM100	LOAD.B	D4,(A0)	SL.W	D4,#8	LOAD.B	D4,(A0)+(D6.W)	; D4 <-- word source	.ELSE	LOAD.B	D4,(A0)+(D6.W)	SL.W	D4,#8	LOAD.B	D4,(A0)		; D4 <-- word source	.ENDIF	SR.W	D4,D5		;  droite3$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	30$	POPM.L	D3,A0,A1	ADD.L	A0,A2		; A0 <-- ^plus  droite	ADD.L	A1,A4		; A1 <-- ^plus  droite	DEC.W	D7		; encore une tranche d'un byte ?	JUMP,NE	25$		; oui => 25$; Effectue le travail de fin.50$:	AND.B	D2,#7		; D2 <-- reste	JUMP,EQ	90$	COMP.B	D0,D1	JUMP,LS	70$				; Ds > Dd :	SUB.B	D2,#8	NEG.B	D2		; D2 <-- (8-r)	LOAD.B	D5,D0	SUB.B	D5,D1		; D5 <-- Ds-Dd	COMP.B	D5,D2	JUMP',HI 65$	SUB.B	D5,D2	NEG.B	D5		; D5 <-- (8-r)-(Ds-Dd)60$:	LOAD.B	D4,(A0)		; D4 <-- byte source	.IF	SM100	SR.B	D4,D5		;  droite de (8-r)-(Ds-Dd)	SL.B	D4,D2		;  gauche de (8-r)	.ELSE	SL.B	D4,D5		;  droite de (8-r)-(Ds-Dd)	SR.B	D4,D2		;  gauche de (8-r)	.ENDIF4$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	60$	JUMP	90$65$:	.IF	SM100	NEG.B	D5	ADD.B	D5,D2	ADD.B	D5,#8		; D5 <-- 8+(8-r)-(Ds-Dd)	.ELSE	ADD.B	D2,#8		; D2 <-- (16-r)	NEG.B	D5	ADD.B	D5,D2		; D5 <-- (16-r)-(Ds-Dd)	.ENDIF66$:	.IF	SM100	LOAD.B	D4,(A0)	SL.W	D4,#8	LOAD.B	D4,(A0)+(D6.W)	; D4 <-- word source	.ELSE	LOAD.B	D4,(A0)+(D6.W)	SL.W	D4,#8	LOAD.B	D4,(A0)		; D4 <-- word source	.ENDIF	.IF	SM100	SR.W	D4,D5		;  droite de 8+(8-r)-(Ds-Dd)	SL.B	D4,D2		;  gauche de (8-r)	.ELSE	SL.W	D4,D5		;  droite de (16-r)-(Ds-Dd)	SR.W	D4,D2		;  gauche de (16-r)	.ENDIF5$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	66$	JUMP	90$70$:				; Ds <= Dd :	LOAD.B	D5,D1	SUB.B	D5,D0		; D5 <-- (Dd-Ds)	COMP.B	D5,D2	JUMP',LO 75$	SUB.B	D5,D2		; D5 <-- (Dd-Ds)-r	SUB.B	D2,#8	NEG.B	D2		; D2 <-- (8-r)72$:	LOAD.B	D4,(A0)		; D4 <-- byte source	.IF	SM100	SR.B	D4,D5		;  droite de (Dd-Ds)-r	SL.B	D4,D2		;  gauche de (8-r)	.ELSE	SL.B	D4,D5		;  droite de (Dd-Ds)-r	SR.B	D4,D2		;  gauche de (8-r)	.ENDIF6$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	72$	JUMP	90$75$:	SUB.B	D2,#8	NEG.B	D2		; D2 <-- (8-r)	.IF	SM100	ADD.B	D5,D2		; D5 <-- (8-r)+(Dd-Ds)	.ELSE	ADD.B	D5,D2		; D5 <-- (8-r)+(Dd-Ds)	ADD.B	D2,#8		; D2 <-- (16-r)	.ENDIF76$:	.IF	SM100	LOAD.B	D4,(A0)	SL.W	D4,#8	LOAD.B	D4,(A0)+(D6.W)	; D4 <-- word source	.ELSE	LOAD.B	D4,(A0)+(D6.W)	SL.W	D4,#8	LOAD.B	D4,(A0)		; D4 <-- word source	.ENDIF	.IF	SM100	SR.W	D4,D5		;  droite de (8-r)-(Dd-Ds)	SL.B	D4,D2		;  gauche de (8-r)	.ELSE	SL.W	D4,D5		;  droite de (8-r)-(Dd-Ds)	SR.W	D4,D2		;  gauche de (16-r)	.ENDIF7$:	NOP			; <<< INSTRUCTION VARIABLE <<<	NOP			; <<< INSTRUCTION VARIABLE <<<	ADD.L	A0,A3		; A0 <-- ^plus bas	ADD.L	A1,A5		; A1 <-- ^plus bas	DEC.W	D3	JUMP,NE	76$;	JUMP	90$90$:	POPM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5,A6	RETADRAST1	=	1$-RASTERADRAST2	=	2$-RASTERADRAST3	=	3$-RASTERADRAST4	=	4$-RASTERADRAST5	=	5$-RASTERADRAST6	=	6$-RASTERADRAST7	=	7$-RASTEROPRAST:	NO